#include <bits/stdc++.h>
using namespace std;
int main()
{
    string a;
    char b;
    while (cin>>a)
        {
            for(int i=0;i<a.length();i++)
                {
                    if(i%2==0)
                    {
                        b=a[i]-'a'+'A';
                        cout<<b;
                    }
                    else
                    {
                        cout<<a[i];
                    }
                }
            cout<<" ";
        }
    return 0;
}
